// app/page.tsx
import { revalidateTag } from 'next/cache';
import { getCachedProducts } from '../lib/db';

export default async function Page() {
  async function syncProducts() {
    'use server';

    // Mark the shared entry stale without making this request recompute it.
    revalidateTag('products', 'max');
  }

  const products = await getCachedProducts();

  return (
    <main className="catalog-shell">
      <header className="catalog-header">
        <div>
          <p className="eyebrow">Operations / Catalog</p>
          <h1>Product catalog</h1>
          <p className="subtitle">Browse pricing and availability across your storefront.</p>
        </div>
        <form action={syncProducts}>
          <button className="sync-button" type="submit">
            <span aria-hidden="true">↻</span>
            Sync latest catalog
          </button>
        </form>
      </header>

      <section className="catalog-toolbar" aria-label="Catalog summary">
        <div>
          <strong>{products.length}</strong>
          <span>Products</span>
        </div>
        <span className="status"><span className="status-dot" />Catalog connected</span>
      </section>

      <section className="table-wrap" aria-label="Products">
        <table>
          <thead>
            <tr>
              <th scope="col">Product</th>
              <th scope="col">SKU</th>
              <th scope="col">Price</th>
              <th scope="col">Availability</th>
              <th scope="col">Source</th>
            </tr>
          </thead>
          <tbody>
            {products.map(product => (
              <tr key={product.id}>
                <td className="product-name"><span className="product-mark">{product.name.slice(0, 1)}</span>{product.name}</td>
                <td className="muted">SKU-{String(product.id).padStart(4, '0')}</td>
                <td>${product.price.toLocaleString('en-US')}.00</td>
                <td><span className="availability"><span className="status-dot" />In stock</span></td>
                <td className="muted">ERP / PIM</td>
              </tr>
            ))}
          </tbody>
        </table>
      </section>
    </main>
  );
}


